'use client';

import { useState, useEffect, useCallback } from 'react';
import { getToken } from '@/lib/api-client';
import { Search, RefreshCw, XCircle, CheckCircle, AlertTriangle, Trash2 } from 'lucide-react';

interface AuditLogItem {
  id: string;
  user_id: string;
  user_email?: string | null;
  user_phone?: string | null;
  action: string;
  resource_type: string | null;
  resource_id: string | null;
  status: string;
  error_message: string | null;
  details: string | null;
  ip_address: string | null;
  user_agent: string | null;
  created_at: string;
}

const actionLabels: Record<string, string> = {
  workflow_run: '工作流调用',
  workflow_stream: '工作流流式调用',
  admin_create_activation_codes: '创建激活码',
  admin_delete_activation_code: '删除激活码',
  admin_grant_credits: '充值积分',
  admin_deactivate_user: '停用用户',
  admin_modify_user: '修改用户',
  admin_delete_audit_log: '删除审计日志',
  admin_clear_audit_logs: '清空审计日志',
};

export default function AdminLogsPage() {
  const [logs, setLogs] = useState<AuditLogItem[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [token, setTokenState] = useState<string | null>(null);
  const [distinctActions, setDistinctActions] = useState<string[]>([]);

  // Filters
  const [filterAction, setFilterAction] = useState('');
  const [filterUserId, setFilterUserId] = useState('');
  const [filterAccount, setFilterAccount] = useState('');
  const [filterStatus, setFilterStatus] = useState('');
  const [filterStartDate, setFilterStartDate] = useState('');
  const [filterEndDate, setFilterEndDate] = useState('');

  const pageSize = 10;

  // Initialize token on mount
  useEffect(() => {
    const t = getToken();
    if (t) setTokenState(t);
  }, []);

  const fetchLogs = useCallback(async () => {
    if (!token) return;
    setLoading(true);
    setError(null);
    try {
      const params = new URLSearchParams({
        page: String(page),
        pageSize: String(pageSize),
      });
      if (filterAction) params.set('action', filterAction);
      if (filterUserId) params.set('userId', filterUserId);
      if (filterAccount) params.set('account', filterAccount);
      if (filterStatus) params.set('status', filterStatus);
      if (filterStartDate) params.set('startDate', filterStartDate);
      if (filterEndDate) params.set('endDate', filterEndDate);

      const res = await fetch(`/api/admin/audit-logs?${params}`, {
        headers: { 'x-session': token },
      });
      if (res.ok) {
        const data = await res.json().catch(() => ({ logs: [], total: 0, distinctActions: [] }));
        setLogs(Array.isArray(data.logs) ? data.logs : []);
        setTotal(data.total ?? 0);
        setDistinctActions(Array.isArray(data.distinctActions) ? data.distinctActions : []);
      } else {
        const errText = await res.text().catch(() => '加载失败');
        setError(errText?.includes('{') ? JSON.parse(errText)?.error || '加载失败' : '加载失败');
      }
    } catch (e: any) {
      setError(e.message || '网络错误');
    }
    setLoading(false);
  }, [token, page, filterAction, filterUserId, filterStatus, filterStartDate, filterEndDate]);

  useEffect(() => {
    if (token) fetchLogs();
  }, [fetchLogs, token]);

  const handleReset = () => {
    setFilterAction('');
    setFilterUserId('');
    setFilterAccount('');
    setFilterStatus('');
    setFilterStartDate('');
    setFilterEndDate('');
    setPage(1);
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('确定删除这条审计日志吗？\n\n此操作不可恢复。')) return;
    try {
      const res = await fetch('/api/admin/audit-logs', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json', 'x-session': token! },
        body: JSON.stringify({ id }),
      });
      const data = await res.json().catch(() => ({} as any));
      if (res.ok && data.success) {
        fetchLogs();
      } else {
        alert(data.error || '删除失败');
      }
    } catch (e: any) {
      alert(e.message || '删除失败');
    }
  };

  const handleClearAll = async () => {
    if (!window.confirm('确定清空全部审计日志吗？\n\n此操作不可恢复，将删除所有历史日志（仅保留本次清空操作的记录）。')) return;
    try {
      const res = await fetch('/api/admin/audit-logs', {
        method: 'DELETE',
        headers: { 'Content-Type': 'application/json', 'x-session': token! },
        body: JSON.stringify({ clearAll: true }),
      });
      const data = await res.json().catch(() => ({} as any));
      if (res.ok && data.success) {
        setPage(1);
        fetchLogs();
      } else {
        alert(data.error || '清空失败');
      }
    } catch (e: any) {
      alert(e.message || '清空失败');
    }
  };

  const totalPages = Math.max(1, Math.ceil(total / pageSize));

  const getActionLabel = (action: string) => actionLabels[action] || action;

  const getStatusIcon = (status: string) => {
    if (status === 'success') return <CheckCircle className="w-3.5 h-3.5 text-green-500" />;
    if (status === 'failure' || status === 'error') return <XCircle className="w-3.5 h-3.5 text-red-500" />;
    return <AlertTriangle className="w-3.5 h-3.5 text-yellow-500" />;
  };

  const formatDetails = (details: unknown) => {
    if (!details) return '-';
    if (typeof details === 'object') {
      return JSON.stringify(details, null, 1);
    }
    if (typeof details === 'string') {
      try {
        const obj = JSON.parse(details);
        return JSON.stringify(obj, null, 1);
      } catch {
        return details;
      }
    }
    return String(details);
  };

  const safeDate = (dateStr: string) => {
    try {
      return new Date(dateStr).toLocaleString('zh-CN');
    } catch {
      return dateStr || '-';
    }
  };

  if (!token) {
    return (
      <div className="flex items-center justify-center py-20">
        <p className="text-gray-400">请先登录管理后台</p>
      </div>
    );
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <h1 className="text-2xl font-semibold text-gray-900">审计日志</h1>
        <div className="flex gap-2">
          <button onClick={handleReset} className="flex items-center gap-1.5 px-3 py-2 border border-gray-300 rounded-md text-sm text-gray-600 hover:bg-gray-50">
            重置筛选
          </button>
          <button onClick={fetchLogs} className="flex items-center gap-1.5 px-3 py-2 border border-gray-300 rounded-md text-sm text-gray-600 hover:bg-gray-50">
            <RefreshCw className="w-3.5 h-3.5" /> 刷新
          </button>
          <button onClick={handleClearAll} className="flex items-center gap-1.5 px-3 py-2 border border-red-300 rounded-md text-sm text-red-600 hover:bg-red-50">
            <Trash2 className="w-3.5 h-3.5" /> 清空日志
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-lg border border-gray-200 p-4 mb-4">
        <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">操作类型</label>
            <select
              value={filterAction}
              onChange={(e) => { setFilterAction(e.target.value); setPage(1); }}
              className="w-full px-2 py-1.5 border border-gray-300 rounded text-xs focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="">全部</option>
              {distinctActions.map((a) => (
                <option key={a} value={a}>{getActionLabel(a)}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">用户 ID</label>
            <input
              type="text"
              value={filterUserId}
              onChange={(e) => { setFilterUserId(e.target.value); setPage(1); }}
              placeholder="输入用户 ID"
              className="w-full px-2 py-1.5 border border-gray-300 rounded text-xs focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">用户账号</label>
            <input
              type="text"
              value={filterAccount}
              onChange={(e) => { setFilterAccount(e.target.value); setPage(1); }}
              placeholder="邮箱或手机号"
              className="w-full px-2 py-1.5 border border-gray-300 rounded text-xs focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">状态</label>
            <select
              value={filterStatus}
              onChange={(e) => { setFilterStatus(e.target.value); setPage(1); }}
              className="w-full px-2 py-1.5 border border-gray-300 rounded text-xs focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="">全部</option>
              <option value="success">成功</option>
              <option value="failure">失败</option>
            </select>
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">开始日期</label>
            <input
              type="date"
              value={filterStartDate}
              onChange={(e) => { setFilterStartDate(e.target.value); setPage(1); }}
              className="w-full px-2 py-1.5 border border-gray-300 rounded text-xs focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-gray-600 mb-1">结束日期</label>
            <input
              type="date"
              value={filterEndDate}
              onChange={(e) => { setFilterEndDate(e.target.value); setPage(1); }}
              className="w-full px-2 py-1.5 border border-gray-300 rounded text-xs focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>
      </div>

      {error && (
        <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-lg text-sm text-red-700">
          {error}
          <button onClick={fetchLogs} className="ml-3 underline">重试</button>
        </div>
      )}

      {/* Table */}
      <div className="bg-white rounded-lg border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-gray-200 bg-gray-50">
                <th className="text-left px-4 py-3 font-medium text-gray-600 w-[160px]">时间</th>
                <th className="text-left px-4 py-3 font-medium text-gray-600">操作类型</th>
                <th className="text-left px-4 py-3 font-medium text-gray-600">用户 ID</th>
                <th className="text-left px-4 py-3 font-medium text-gray-600">资源</th>
                <th className="text-left px-4 py-3 font-medium text-gray-600">状态</th>
                <th className="text-left px-4 py-3 font-medium text-gray-600">详情</th>
                <th className="text-left px-4 py-3 font-medium text-gray-600 w-[80px]">操作</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={7} className="text-center py-8 text-gray-400">加载中...</td></tr>
              ) : logs.length === 0 ? (
                <tr><td colSpan={7} className="text-center py-8 text-gray-400">暂无审计日志</td></tr>
              ) : (
                logs.map((log) => (
                  <tr key={log.id} className="border-b border-gray-100 hover:bg-gray-50">
                    <td className="px-4 py-3 text-xs text-gray-500 whitespace-nowrap">
                      {safeDate(log.created_at)}
                    </td>
                    <td className="px-4 py-3">
                      <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs bg-gray-100 text-gray-700">
                        {getActionLabel(log.action)}
                      </span>
                    </td>
                    <td className="px-4 py-3 font-mono text-xs max-w-[180px] break-all">
                      {log.user_id}
                      {(log.user_email || log.user_phone) && (
                        <div className="text-[11px] text-gray-400 mt-0.5 truncate">
                          {log.user_email || log.user_phone}
                        </div>
                      )}
                    </td>
                    <td className="px-4 py-3 text-xs text-gray-500">
                      {log.resource_type ? `${log.resource_type}${log.resource_id ? `: ${String(log.resource_id).slice(0, 12)}...` : ''}` : '-'}
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-1">
                        {getStatusIcon(log.status)}
                        <span className={`text-xs ${log.status === 'success' ? 'text-green-700' : log.status === 'failure' ? 'text-red-700' : 'text-yellow-700'}`}>
                          {log.status === 'success' ? '成功' : log.status === 'failure' ? '失败' : log.status}
                        </span>
                      </div>
                      {log.error_message && (
                        <div className="text-xs text-red-500 mt-0.5 max-w-[200px] truncate" title={log.error_message}>
                          {log.error_message}
                        </div>
                      )}
                    </td>
                    <td className="px-4 py-3 text-xs text-gray-500 max-w-[250px]">
                      <pre className="whitespace-pre-wrap break-all text-[11px] leading-relaxed max-h-16 overflow-y-auto">
                        {formatDetails(log.details)}
                      </pre>
                    </td>
                    <td className="px-4 py-3">
                      <button
                        onClick={() => handleDelete(log.id)}
                        className="text-red-500 hover:text-red-700"
                        title="删除该日志"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {totalPages > 1 && (
          <div className="flex items-center justify-between px-4 py-3 border-t border-gray-200 bg-gray-50">
            <span className="text-xs text-gray-500">共 {total} 条</span>
            <div className="flex gap-1">
              <button disabled={page <= 1} onClick={() => setPage(page - 1)} className="px-3 py-1 text-xs border border-gray-300 rounded disabled:opacity-40 hover:bg-gray-100">上一页</button>
              <span className="px-3 py-1 text-xs text-gray-600">{page}/{totalPages}</span>
              <button disabled={page >= totalPages} onClick={() => setPage(page + 1)} className="px-3 py-1 text-xs border border-gray-300 rounded disabled:opacity-40 hover:bg-gray-100">下一页</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
